import{_ as a,c as m,o as e,b as t}from"./app.aaa68922.js";const l='{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 4","description":"","frontmatter":{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 4","subtitle":"\u0428\u0438\u0432\u0430 \u0441\u0443\u0442\u0440\u0430 \u0432\u0438\u043C\u0430\u0440\u0448\u0438\u043D\u0438. \u0413\u043B\u0430\u0432\u0430 1.","toc":true,"tags":"vim-1","sans":"\u091C\u094D\u091E\u093E\u0928\u093E\u0927\u093F\u0937\u094D\u0920\u093E\u0928\u0902 \u092E\u093E\u0924\u0943\u0915\u093E","trans":"J\xF1\u0101n\u0101dhi\u1E63\u1E6Dh\u0101na\u1E41 m\u0101t\u1E5Bk\u0101","date":"2021-02-21T00:00:00.000Z"},"headers":[],"relativePath":"texts/shiva-sutra-vimarshini/1/4.md"}',i={},r=t('<div class="stanza"><a href="#s1.4" id="s1.4" class="num">1.4</a><div class="sans"><p>\u0905\u0925 \u0915\u0925\u092E\u0938\u094D\u092F\u093E\u091C\u094D\u091E\u093E\u0928\u093E\u0924\u094D\u092E\u0915\u091C\u094D\u091E\u093E\u0928\u092F\u094B\u0928\u093F\u0935\u0930\u094D\u0917\u0915\u0932\u093E\u0936\u0930\u0940\u0930\u0930\u0942\u092A\u0938\u094D\u092F \u0924\u094D\u0930\u093F\u0935\u093F\u0927\u0938\u094D\u092F \u092E\u0932\u0938\u094D\u092F \u092C\u0928\u094D\u0927\u0915\u0924\u094D\u0935\u092E\u093F\u0924\u094D\u092F\u093E\u0939\u2014</p><blockquote><p><strong>\u091C\u094D\u091E\u093E\u0928\u093E\u0927\u093F\u0937\u094D\u0920\u093E\u0928\u0902 \u092E\u093E\u0924\u0943\u0915\u093E\u0965\u096A\u0965</strong></p></blockquote><p>\u092F\u0926\u0947\u0924\u0924\u094D\u0924\u094D\u0930\u093F\u0935\u093F\u0927\u092E\u0932\u0938\u094D\u0935\u0930\u0942\u092A\u092E\u092A\u0942\u0930\u094D\u0923\u092E\u094D\u092E\u0928\u094D\u092F\u0924\u093E\u092D\u093F\u0928\u094D\u0928\u0935\u0947\u0926\u094D\u092F\u092A\u094D\u0930\u0925\u093E\u0936\u0941\u092D\u093E\u0936\u0941\u092D\u0935\u093E\u0938\u0928\u093E\u0924\u094D\u092E\u0915\u0902 \u0935\u093F\u0935\u093F\u0927\u0902 \u091C\u094D\u091E\u093E\u0928\u0930\u0942\u092A\u092E\u0941\u0915\u094D\u0924\u0902 \u0924\u0938\u094D\u092F\u093E\u0926\u093F\u0915\u094D\u0937\u093E\u0928\u094D\u0924\u0930\u0942\u092A\u093E\u091C\u094D\u091E\u093E\u0924\u093E \u092E\u093E\u0924\u093E \u092E\u093E\u0924\u0943\u0915\u093E \u0935\u093F\u0936\u094D\u0935\u091C\u0928\u0928\u0940 \u0924\u0924\u094D\u0924\u0924\u094D\u0938\u0919\u094D\u0915\u0941\u091A\u093F\u0924\u0935\u0947\u0926\u094D\u092F\u093E\u092D\u093E\u0938\u093E\u0924\u094D\u092E\u0928\u094B \u091C\u094D\u091E\u093E\u0928\u0938\u094D\u092F \u0905\u092A\u0942\u0930\u094D\u0923\u094B\u093D\u0938\u094D\u092E\u093F \u0915\u094D\u0937\u093E\u092E\u0903 \u0938\u094D\u0925\u0942\u0932\u094B \u0935\u093E\u0938\u094D\u092E\u094D\u092F\u0917\u094D\u0928\u093F\u0937\u094D\u091F\u094B\u092E\u092F\u093E\u091C\u094D\u092F\u0938\u094D\u092E\u0940\u0924\u094D\u092F\u093E\u0926\u093F \u0924\u0924\u094D\u0924\u0926\u0935\u093F\u0915\u0932\u094D\u092A\u0915\u0938\u0935\u093F\u0915\u0932\u094D\u092A\u0915\u093E\u0935\u092D\u093E\u0938\u092A\u0930\u093E\u092E\u0930\u094D\u0936\u092E\u092F\u0938\u094D\u092F \u0924\u0924\u094D\u0924\u0926\u094D\u0935\u093E\u091A\u0915\u0936\u092C\u094D\u0926\u093E\u0928\u0941\u0935\u0947\u0927\u0926\u094D\u0935\u093E\u0930\u0947\u0923 \u0936\u094B\u0915\u0938\u094D\u092E\u092F\u0939\u0930\u094D\u0937\u0930\u093E\u0917\u093E\u0926\u093F\u0930\u0942\u092A\u0924\u093E\u092E\u093E\u0926\u0927\u093E\u0928\u093E</p><blockquote><p>\u0915\u0930\u0928\u094D\u0927\u094D\u0930\u091A\u093F\u0924\u093F\u092E\u0927\u094D\u092F\u0938\u094D\u0925\u093E \u092C\u094D\u0930\u0939\u094D\u092E\u092A\u093E\u0936\u093E\u0935\u0932\u092E\u094D\u092C\u093F\u0915\u093E\u0903|<br> \u092A\u0940\u0920\u0947\u0936\u094D\u0935\u0930\u094D\u092F\u094B \u092E\u0939\u093E\u0918\u094B\u0930\u093E \u092E\u094B\u0939\u092F\u0928\u094D\u0924\u093F \u092E\u0941\u0939\u0941\u0930\u094D\u092E\u0941\u0939\u0941\u0903\u0965</p></blockquote><p>\u0907\u0924\u093F \u0936\u094D\u0930\u0940\u0924\u093F\u092E\u093F\u0930\u094B\u0926\u094D\u0918\u093E\u091F\u092A\u094D\u0930\u094B\u0915\u094D\u0924\u0928\u0940\u0924\u094D\u092F\u093E \u0935\u0930\u094D\u0917\u0915\u0932\u093E\u0926\u094D\u092F\u0927\u093F\u0937\u094D\u0920\u093E\u0924\u0943\u092C\u094D\u0930\u093E\u0939\u094D\u092E\u094D\u092F\u093E\u0926\u093F\u0936\u0915\u094D\u0924\u093F\u0936\u094D\u0930\u0947\u0923\u0940\u0936\u094B\u092D\u093F\u0928\u0940 \u0936\u094D\u0930\u0940\u0938\u0930\u094D\u0935\u0935\u0940\u0930\u093E\u0926\u094D\u092F\u093E\u0917\u092E\u092A\u094D\u0930\u0938\u093F\u0926\u094D\u0927\u0932\u093F\u092A\u093F\u0915\u094D\u0930\u092E\u0938\u0928\u094D\u0928\u093F\u0935\u0947\u0936\u094B\u0924\u094D\u0925\u093E\u092A\u093F\u0915\u093E\u092E\u094D\u092C\u093E\u091C\u094D\u092F\u0947\u0937\u094D\u0920\u093E\u0930\u094C\u0926\u094D\u0930\u0940\u0935\u093E\u092E\u093E\u0916\u094D\u092F\u0936\u0915\u094D\u0924\u093F\u091A\u0915\u094D\u0930\u091A\u0941\u092E\u094D\u092C\u093F\u0924\u093E \u0936\u0915\u094D\u0924\u093F\u0930\u0927\u093F\u0937\u094D\u0920\u093E\u0924\u094D\u0930\u0940 \u0924\u0926\u0927\u093F\u0937\u094D\u0920\u093E\u0928\u093E\u0926\u0947\u0935 \u0939\u094D\u092F\u0928\u094D\u0924\u0930\u092D\u0947\u0926\u093E\u0928\u0941\u0938\u0928\u094D\u0927\u093F\u0935\u0928\u094D\u0927\u094D\u092F\u0924\u094D\u0935\u093E\u0924\u094D\u0915\u094D\u0937\u0923\u092E\u092A\u094D\u092F\u0932\u092C\u094D\u0927\u0935\u093F\u0936\u094D\u0930\u093E\u0928\u094D\u0924\u0940\u0928\u093F \u092C\u0939\u093F\u0930\u094D\u092E\u0941\u0916\u093E\u0928\u094D\u092F\u0947\u0935 \u091C\u094D\u091E\u093E\u0928\u093E\u0928\u0940\u0924\u093F \u092F\u0941\u0915\u094D\u0924\u0948\u0935 \u090F\u0937\u093E\u0902 \u092C\u0928\u094D\u0927\u0915\u0924\u094D\u0935\u094B\u0915\u094D\u0924\u093F\u0903\u0964 \u090F\u0924\u091A\u094D\u091A</p><blockquote><p>\u0936\u092C\u094D\u0926\u0930\u093E\u0936\u093F\u0938\u092E\u0941\u0924\u094D\u0925\u0938\u094D\u092F...\u0964</p></blockquote><p>\u0907\u0924\u093F \u0915\u093E\u0930\u093F\u0915\u092F\u093E</p><blockquote><p>\u0938\u094D\u0935\u0930\u0942\u092A\u093E\u0935\u0930\u0923\u0947 \u091A\u093E\u0938\u094D\u092F \u0936\u0915\u094D\u0924\u092F\u0903 \u0938\u0924\u0924\u094B\u0924\u094D\u0925\u093F\u0924\u093E\u0903\u0964</p></blockquote><p>\u0907\u0924\u093F \u091A \u0915\u093E\u0930\u093F\u0915\u092F\u093E \u0938\u0919\u094D\u0917\u0943\u0939\u0940\u0924\u092E\u094D\u0965\u096A\u0965</p></div><div class="trans"><p>Atha kathamasy\u0101j\xF1\u0101n\u0101tmakaj\xF1\u0101nayonivargakal\u0101\u015Bar\u012Brar\u016Bpasya trividhasya malasya bandhakatvamity\u0101ha\u2014</p><blockquote><p><strong>J\xF1\u0101n\u0101dhi\u1E63\u1E6Dh\u0101na\u1E41 m\u0101t\u1E5Bk\u0101||4||</strong></p></blockquote><p>Yadetattrividhamalasvar\u016Bpamap\u016Br\u1E47ammanyat\u0101bhinnavedyaprath\u0101\u015Bubh\u0101\u015Bubhav\u0101san\u0101tmaka\u1E41 vividha\u1E41 j\xF1\u0101nar\u016Bpamukta\u1E41 tasy\u0101dik\u1E63\u0101ntar\u016Bp\u0101j\xF1\u0101t\u0101 m\u0101t\u0101 m\u0101t\u1E5Bk\u0101 vi\u015Bvajanan\u012B tattatsa\u1E45kucitavedy\u0101bh\u0101s\u0101tmano j\xF1\u0101nasya ap\u016Br\u1E47o&#39;smi k\u1E63\u0101ma\u1E25 sth\u016Blo v\u0101smyagni\u1E63\u1E6Domay\u0101jyasm\u012Bty\u0101di tattadavikalpakasavikalpak\u0101vabh\u0101sapar\u0101mar\u015Bamayasya tattadv\u0101caka\u015Babd\u0101nuvedhadv\u0101re\u1E47a \u015Bokasmayahar\u1E63ar\u0101g\u0101dir\u016Bpat\u0101m\u0101dadh\u0101n\u0101</p><blockquote><p>Karandhracitimadhyasth\u0101 brahmap\u0101\u015B\u0101valambik\u0101\u1E25|<br> P\u012B\u1E6Dhe\u015Bvaryo mah\u0101ghor\u0101 mohayanti muhurmuhu\u1E25||</p></blockquote><p>iti \u015Br\u012Btimirodgh\u0101\u1E6Daproktan\u012Bty\u0101 vargakal\u0101dyadhi\u1E63\u1E6Dh\u0101t\u1E5Bbr\u0101hmy\u0101di\u015Bakti\u015Bre\u1E47\u012B\u015Bobhin\u012B \u015Br\u012Bsarvav\u012Br\u0101dy\u0101gamaprasiddhalipikramasannive\u015Botth\u0101pik\u0101mb\u0101jye\u1E63\u1E6Dh\u0101raudr\u012Bv\u0101m\u0101khya\u015Bakticakracumbit\u0101 \u015Baktiradhi\u1E63\u1E6Dh\u0101tr\u012B tadadhi\u1E63\u1E6Dh\u0101n\u0101deva hyantarabhed\u0101nusandhivandhyatv\u0101tk\u1E63a\u1E47amapyalabdhavi\u015Br\u0101nt\u012Bni bahirmukh\u0101nyeva j\xF1\u0101n\u0101n\u012Bti yuktaiva e\u1E63\u0101\u1E41 bandhakatvokti\u1E25| Etacca</p><blockquote><p>\u015Aabdar\u0101\u015Bisamutthasya...|</p></blockquote><p>iti k\u0101rikay\u0101</p><blockquote><p>Svar\u016Bp\u0101vara\u1E47e c\u0101sya \u015Baktaya\u1E25 satatotthit\u0101\u1E25|</p></blockquote><p>iti ca k\u0101rikay\u0101 sa\u1E45g\u1E5Bh\u012Btam||4||</p></div><p>&quot;\u0422\u0435\u043F\u0435\u0440\u044C <em>(atha)</em>, \u043A\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C <em>(katham)</em> (\u044D\u0442\u043E) <em>(asya)</em> \u0442\u0440\u043E\u0439\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0435 <em>(trividhasya)</em> mala, \u0438\u043B\u0438 \u0437\u0430\u0433\u0440\u044F\u0437\u043D\u0435\u043D\u0438\u0435 <em>(malasya)</em>, \u0447\u044C\u0435\u0439 \u0444\u043E\u0440\u043C\u043E\u0439 <em>(r\u016Bpasya)</em> \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0437\u043D\u0430\u043D\u0438\u0435 <em>(j\xF1\u0101na)</em>, \u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0435\u0435 <em>(\u0101tmaka)</em> \u0438\u0437 aj\xF1\u0101na, \u0438\u043B\u0438 \u043D\u0435\u0432\u0435\u0434\u0435\u043D\u0438\u044F --\u0442.\u0435. \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0433\u043E \u0437\u043D\u0430\u043D\u0438\u044F-- <em>(aj\xF1\u0101na)</em>, \u0419\u043E\u043D\u0438\u0432\u0430\u0440\u0433\u0438 (Yonivarga) --\u041C\u0430\u0439\u0438 (M\u0101y\u0101) \u0438 \u0435\u0435 \u043E\u0442\u043F\u0440\u044B\u0441\u043A\u043E\u0432, \u0442.\u0435. \u041C\u0430\u0439\u0438\u044F\u0439\u043C\u0430\u043B\u044B (M\u0101y\u012Byamala)-- <em>(yoni-varga)</em>, [\u0438] \u041A\u0430\u043B\u0430\u0448\u0430\u0440\u0438\u0440\u044B (Kal\u0101\u015Bar\u012Bra) --\u0447\u044C\u0435\u0439 \u0444\u043E\u0440\u043C\u043E\u0439 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0434\u0435\u044F\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u044C, \u0442.\u0435. \u041A\u0430\u0440\u043C\u0430\u043C\u0430\u043B\u0430 (K\u0101rmamala)-- <em>(kal\u0101-\u015Bar\u012Bra)</em>, \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u043E\u043A\u043E\u0432\u0430\u043C\u0438 <em>(bandhakatvam... iti)</em> [\u0434\u043B\u044F \u0438\u043D\u0434\u0438\u0432\u0438\u0434\u0443\u0430\u043B\u044C\u043D\u043E\u0439 \u0434\u0443\u0448\u0438?&quot;. \u0410\u0432\u0442\u043E\u0440 \u015Aivas\u016Btra-s, \u0442.\u0435. \u0428\u0438\u0432\u0430] \u0441\u043A\u0430\u0437\u0430\u043B <em>(\u0101ha)</em>\u2014</p><blockquote><p><strong>\u041E\u0441\u043D\u043E\u0432\u043E\u0439 <em>(adhi\u1E63\u1E6Dh\u0101nam)</em> [\u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0433\u043E, \u0438\u043B\u0438 \u0441\u043E\u043A\u0440\u0430\u0449\u0435\u043D\u043D\u043E\u0433\u043E] \u0437\u043D\u0430\u043D\u0438\u044F <em>(j\xF1\u0101na)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u043D\u0435\u043F\u043E\u043D\u044F\u0442\u0430\u044F\xA0\u041C\u0430\u0442\u044C <em>(m\u0101t\u1E5Bk\u0101)</em>||4||</strong></p></blockquote><p>\u0422\u043E <em>(etad)</em>, \u0447\u0442\u043E <em>(yad)</em> \u0431\u044B\u043B\u043E \u043E\u043F\u0438\u0441\u0430\u043D\u043E [\u0440\u0430\u043D\u0435\u0435] <em>(uktam)</em>, - [\u044D\u0442\u043E] \u0440\u0430\u0437\u043D\u043E\u043E\u0431\u0440\u0430\u0437\u043D\u044B\u0435 <em>(vividham)</em> \u0444\u043E\u0440\u043C\u044B <em>(r\u016Bpam)</em> [\u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0433\u043E] \u0437\u043D\u0430\u043D\u0438\u044F <em>(j\xF1\u0101na)</em>, \u0447\u044C\u0435\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u043E\u0439 <em>(sva-r\u016Bpam)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0442\u0440\u043E\u0439\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0435 <em>(trividha)</em> mala --\u0437\u0430\u0433\u0440\u044F\u0437\u043D\u0435\u043D\u0438\u0435-- <em>(mala)</em>, \u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0435\u0435 <em>(\u0101tmakam)</em> \u0438\u0437 [1] \u0430\u043A\u0442\u0430 \u0440\u0430\u0441\u0441\u043C\u043E\u0442\u0440\u0435\u043D\u0438\u044F [\u0441\u0435\u0431\u044F] <em>(manyat\u0101)</em> \u043A\u0430\u043A \u043D\u0435\u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u043E\u0433\u043E <em>(ap\u016Br\u1E47am)</em> --\u0442.\u0435. \u0410\u043D\u0430\u0432\u0430\u043C\u0430\u043B\u0430 (\u0100\u1E47avamala)--, [2] \u0440\u0430\u0441\u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0435\u043D\u0438\u044F <em>(prath\u0101)</em> \u043E\u0449\u0443\u0449\u0435\u043D\u0438\u044F <em>(vedya)</em> \u0434\u0438\u0444\u0444\u0435\u0440\u0435\u043D\u0446\u0438\u0430\u0446\u0438\u0438 <em>(bhinna)</em> --\u0442.\u0435. M\u0101y\u012Byamala--, [3] \u0445\u043E\u0440\u043E\u0448\u0438\u0445 <em>(\u015Bubha)</em> [\u0438] \u043F\u043B\u043E\u0445\u0438\u0445 <em>(a\u015Bubha)</em> V\u0101san\u0101-s, \u0438\u043B\u0438 \u0442\u0435\u043D\u0434\u0435\u043D\u0446\u0438\u0439, \u043D\u0430\u043A\u043E\u043F\u043B\u0435\u043D\u043D\u044B\u0445 \u0432 \u043A\u0430\u0443\u0437\u0430\u043B\u044C\u043D\u043E\u043C (\u043F\u0440\u0438\u0447\u0438\u043D\u043D\u043E\u043C) \u0442\u0435\u043B\u0435, [\u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u043F\u0440\u0438\u0432\u043E\u0434\u044F\u0442 \u043A \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u0438\u044E \u0445\u043E\u0440\u043E\u0448\u0438\u0445 \u0438 \u043F\u043B\u043E\u0445\u0438\u0445 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0439 \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0435\u043D\u043D\u043E] <em>(v\u0101san\u0101)</em>^ --\u0442.\u0435. K\u0101rmamala--. \u042D\u0442\u043E [\u0442\u0440\u043E\u0439\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0435 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0435 \u0437\u043D\u0430\u043D\u0438\u0435] <em>(tasya)</em>, \u041C\u0430\u0442\u0440\u0438\u043A\u0430 (M\u0101t\u1E5Bk\u0101) <em>(m\u0101t\u1E5Bk\u0101)</em>, \u0418\u0441\u0442\u043E\u0447\u043D\u0438\u043A <em>(janan\u012B)</em> \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439 <em>(vi\u015Bva)</em>, [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u043D\u0435\u0438\u0437\u0432\u0435\u0441\u0442\u043D\u043E\u0439 <em>(aj\xF1\u0101t\u0101)</em> \u041C\u0430\u0442\u0435\u0440\u044C\u044E <em>(m\u0101t\u0101)</em>, [\u0438] \u0415\u0435 \u0444\u043E\u0440\u043C\u0430 <em>(r\u016Bp\u0101)</em> \u043D\u0430\u0447\u0438\u043D\u0430\u0435\u0442\u0441\u044F <em>(\u0101di)</em> \u0441 &quot;a&quot; <em>(a)</em> [\u0438] \u0437\u0430\u043A\u0430\u043D\u0447\u0438\u0432\u0430\u0435\u0442\u0441\u044F &quot;k\u1E63a&quot; <em>(k\u1E63a)</em>. [\u041E\u043D\u0430 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u041C\u0430\u0442\u0435\u0440\u044C\u044E] \u0437\u043D\u0430\u043D\u0438\u044F <em>(j\xF1\u0101nasya)</em>, \u0447\u044C\u044F \u043F\u0440\u0438\u0440\u043E\u0434\u0430 <em>(\u0101tmana\u1E25)</em> [\u0435\u0441\u0442\u044C] \u0432\u0441\u043F\u044B\u0448\u043A\u0430 <em>(\u0101bh\u0101sa)</em> \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u0445 <em>(tad tad)</em> \u0441\u043E\u043A\u0440\u0430\u0449\u0435\u043D\u043D\u044B\u0445/\u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u044B\u0445 <em>(sa\u1E45kucita)</em> \u043F\u043E\u0437\u043D\u0430\u043D\u0438\u0439 <em>(vedy\u0101)</em>. [\u042D\u0442\u043E \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0435 \u0437\u043D\u0430\u043D\u0438\u0435, \u0438\u043B\u0438 \u043F\u043E\u0437\u043D\u0430\u043D\u0438\u0435 \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0432 \u0444\u043E\u0440\u043C\u0435] &quot;\u042F <em>(asmi)</em> \u043D\u0435\u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u044B\u0439 <em>(ap\u016Br\u1E47a\u1E25)</em>&quot;, &quot;\u042F <em>(asmi)</em> \u0442\u043E\u043D\u043A\u0438\u0439 <em>(k\u1E63\u0101ma\u1E25)</em>&quot; \u0438\u043B\u0438 <em>(v\u0101)</em> &quot;\u042F <em>(asmi)</em> \u0442\u043E\u043B\u0441\u0442\u044B\u0439 <em>(sth\u016Bla\u1E25)</em>&quot;, &quot;\u042F <em>(asmi)</em> \u0438\u0441\u043F\u043E\u043B\u043D\u0438\u0442\u0435\u043B\u044C <em>(y\u0101j\u012B)</em> Agni\u1E63\u1E6Doma \u0436\u0435\u0440\u0442\u0432\u043E\u043F\u0440\u0438\u043D\u043E\u0448\u0435\u043D\u0438\u044F <em>(agni\u1E63\u1E6Doma)</em>&quot; \u0438 \u0442\u0430\u043A \u0434\u0430\u043B\u0435\u0435 <em>(iti \u0101di)</em>. [\u042D\u0442\u043E \u0437\u043D\u0430\u043D\u0438\u0435] \u0441\u0444\u043E\u0440\u043C\u0438\u0440\u043E\u0432\u0430\u043D\u043E <em>(mayasya)</em> \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u043C\u0438 <em>(tad tad)</em> \u0441\u043E\u043E\u0431\u0440\u0430\u0436\u0435\u043D\u0438\u044F\u043C\u0438 <em>(par\u0101mar\u015Ba)</em>, [\u043D\u0435\u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0438\u0437 \u043A\u043E\u0442\u043E\u0440\u044B\u0445] \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F <em>(avabh\u0101sa)</em> \u0431\u0435\u0437 \u043C\u0435\u043D\u0442\u0430\u043B\u044C\u043D\u044B\u0445 \u0438\u0437\u043C\u0435\u043D\u0435\u043D\u0438\u0439 --\u0442.\u0435. \u043A\u0430\u043A \u043F\u043E\u043D\u044F\u0442\u0438\u044F, \u0432\u044B\u0445\u043E\u0434\u044F\u0449\u0438\u0435 \u0437\u0430 \u043F\u0440\u0435\u0434\u0435\u043B\u044B \u043E\u0431\u044B\u0447\u043D\u043E\u0433\u043E \u0443\u043C\u0430-- <em>(a-vikalpaka)</em>, [\u0432 \u0442\u043E \u0432\u0440\u0435\u043C\u044F \u043A\u0430\u043A \u0434\u0440\u0443\u0433\u0438\u0435] \u043E\u0431\u043B\u0430\u0434\u0430\u044E\u0442 \u043C\u0435\u043D\u0442\u0430\u043B\u044C\u043D\u044B\u043C\u0438 \u0438\u0437\u043C\u0435\u043D\u0435\u043D\u0438\u044F\u043C\u0438 --\u0442.\u0435. \u043A\u043E\u043D\u043A\u0440\u0435\u0442\u043D\u043E \u0441\u0444\u043E\u0440\u043C\u0443\u043B\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u044B\u043C\u0438 \u043C\u044B\u0441\u043B\u044F\u043C\u0438-- <em>(sa-vikalpaka)</em>, [\u0438] \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C <em>(dv\u0101re\u1E47a)</em> \u043F\u0440\u043E\u043D\u0438\u043A\u043D\u043E\u0432\u0435\u043D\u0438\u044F <em>(anuvedha)</em> \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u0445 <em>(tad tad)</em> \u0437\u0432\u0443\u043A\u043E\u0432 <em>(\u015Babda)</em> (\u0438) \u0441\u043B\u043E\u0432 <em>(v\u0101caka)</em> [\u0432 \u0443\u043C \u0442\u043E\u0433\u043E, \u043A\u0442\u043E \u0441\u043B\u044B\u0448\u0438\u0442,] \u043F\u043E\u0440\u043E\u0436\u0434\u0430\u0435\u0442\u0441\u044F <em>(dh\u0101n\u0101)</em> \u0438\u043D\u0442\u043E\u043A\u0441\u0438\u043A\u0430\u0446\u0438\u044F <em>(m\u0101da)</em> \u0432 \u0444\u043E\u0440\u043C\u0435 <em>(r\u016Bpat\u0101)</em> \u043F\u0435\u0447\u0430\u043B\u0438 <em>(\u015Boka)</em>, \u0432\u044B\u0441\u043E\u043A\u043E\u043C\u0435\u0440\u0438\u044F <em>(smaya)</em>, \u0440\u0430\u0434\u043E\u0441\u0442\u0438 <em>(har\u1E63a)</em>, \u0441\u0442\u0440\u0430\u0441\u0442\u0438 <em>(r\u0101ga)</em>, \u0438 \u0442.\u0434. <em>(\u0101di)</em>. \u0421\u043E\u0433\u043B\u0430\u0441\u043D\u043E \u043D\u0430\u0441\u0442\u0430\u0432\u043B\u0435\u043D\u0438\u044F\u043C <em>(n\u012Bty\u0101)</em>, \u0438\u0437\u043B\u043E\u0436\u0435\u043D\u043D\u044B\u043C <em>(prokta)</em> \u0432 \u0443\u0432\u0430\u0436\u0430\u0435\u043C\u043E\u043C <em>(\u015Br\u012B)</em> Timirodgh\u0101\u1E6Da <em>(timirodgh\u0101\u1E6Da)</em>:</p><blockquote><p>&quot;Mah\u0101ghor\u0101-s --\u0442.\u0435. &quot;\u043D\u0435\u0432\u0435\u0440\u043E\u044F\u0442\u043D\u043E \u0443\u0436\u0430\u0441\u043D\u044B\u0435&quot;-- <em>(mah\u0101ghor\u0101\u1E25)</em>, [\u044D\u0442\u043E \u0442\u0435 \u015Bakti-s, \u0438\u043B\u0438 \u0441\u0438\u043B\u044B], \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0442 <em>(sth\u0101\u1E25)</em>\xA0\u0432 \u0441\u0435\u0440\u0434\u0446\u0435\u0432\u0438\u043D\u0435\xA0<em>(madhya)</em> \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(citi)</em> \u0432 Karandhra --\u0442.\u0435. \u0432 Brahmarandhra-- <em>(ka-randhra)</em>^, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u043F\u043E\u0434\u0432\u0435\u0448\u0438\u0432\u0430\u044E\u0442\xA0<em>(avalambik\u0101\u1E25)</em>\xA0\u0430\u0440\u043A\u0430\u043D\u043E\u043C\xA0\u0411\u0440\u0430\u0445\u043C\u044B (Brahm\u0101) <em>(brahma-p\u0101\u015Ba)</em> [\u0438] \u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u043F\u043E\u0432\u0435\u043B\u0438\u0442\u0435\u043B\u044C\u043D\u0438\u0446\u0430\u043C\u0438 <em>(\u012B\u015Bvarya\u1E25)</em> p\u012B\u1E6Dha-s, \u0438\u043B\u0438 \u043E\u043F\u043E\u0440/\u0441\u0438\u0434\u0435\u043D\u0438\u0439\xA0--\u043E\u0440\u0433\u0430\u043D\u043E\u0432 \u0447\u0443\u0432\u0441\u0442\u0432-- <em>(p\u012B\u1E6Dha)</em>, \u0432\u0432\u043E\u0434\u044F\u0442 \u0432 \u0437\u0430\u0431\u043B\u0443\u0436\u0434\u0435\u043D\u0438\u0435 <em>(mohayanti)</em> \u0441\u043D\u043E\u0432\u0430 \u0438 \u0441\u043D\u043E\u0432\u0430 <em>(muhur... muhur... iti)</em>&quot;||</p></blockquote><p>[M\u0101t\u1E5Bk\u0101] \u0441\u0438\u044F\u0435\u0442 <em>(\u015Bobhin\u012B)</em> \u0432 \u0433\u0440\u0443\u043F\u043F\u0435 <em>(\u015Bre\u1E47\u012B)</em> \u0441\u0438\u043B <em>(\u015Bakti)</em>, [\u0442\u0430\u043A\u0438\u0445 \u043A\u0430\u043A] Br\u0101hm\u012B <em>(br\u0101hm\u012B)</em>, \u0438 \u0442.\u0434. <em>(\u0101di)</em>, \u0433\u043B\u0430\u0432\u0435\u043D\u0441\u0442\u0432\u0443\u044E\u0449\u0438\u0445 <em>(adhi\u1E63\u1E6Dh\u0101t\u1E5B)</em> \u043D\u0430\u0434 \u0433\u0440\u0443\u043F\u043F\u0430\u043C\u0438 \u0431\u0443\u043A\u0432 <em>(varga)</em>, Kal\u0101-s --\u043F\u044F\u0442\u044C\u044E \u043F\u0435\u0440\u0432\u043E\u0437\u0434\u0430\u043D\u043D\u044B\u043C\u0438 \u0441\u0438\u043B\u0430\u043C\u0438-- <em>(kal\u0101)</em>, \u0438 \u0442.\u043F. <em>(\u0101di)</em>. \u041E\u043D\u0430 \u043F\u0440\u043E\u0431\u0443\u0436\u0434\u0430\u0435\u0442, \u0438\u043B\u0438 \u043E\u0436\u0438\u0432\u043B\u044F\u0435\u0442 [\u0436\u0438\u0432\u044B\u0445 \u0441\u0443\u0449\u0435\u0441\u0442\u0432] <em>(utth\u0101pik\u0101)</em> \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u0440\u0430\u0441\u043F\u043E\u043B\u043E\u0436\u0435\u043D\u0438\u044F <em>(sannive\u015Ba)</em> \u043F\u043E\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u0438 <em>(krama)</em> \u0431\u0443\u043A\u0432 <em>(lipi)</em>, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u0430 <em>(prasiddha)</em> \u0432 \u0100gama-s --\u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u043D\u044B\u0445 \u0441\u0432\u044F\u0449\u0435\u043D\u043D\u044B\u0445 \u041F\u0438\u0441\u0430\u043D\u0438\u044F\u0445-- <em>(\u0101gama)</em>, [\u0442\u0430\u043A\u0438\u0445 \u043A\u0430\u043A] \u043F\u043E\u0447\u0442\u0435\u043D\u043D\u044B\u0439 <em>(\u015Br\u012B)</em> Sarvav\u012Bra <em>(sarvav\u012Bra)</em>, \u0438 \u0434\u0440. <em>(\u0101di)</em>. \u041E\u043D\u0430 \u0442\u0435\u0441\u043D\u043E \u0441\u0432\u044F\u0437\u0430\u043D\u0430 <em>(cumbit\u0101)</em> \u0441 \u0433\u0440\u0443\u043F\u043F\u043E\u0439 <em>(cakra)</em> \u0441\u0438\u043B <em>(\u015Bakti)</em>, \u0438\u043C\u0435\u043D\u0430 \u043A\u043E\u0442\u043E\u0440\u044B\u0445 <em>(\u0101khya)</em> Amb\u0101 <em>(amb\u0101)</em>, Jye\u1E63\u1E6Dh\u0101 <em>(jye\u1E63\u1E6Dh\u0101)</em>, Raudr\u012B <em>(raudr\u012B)</em> (\u0438) V\u0101m\u0101 <em>(v\u0101m\u0101)</em>. [\u041F\u0440\u043E\u0449\u0435 \u0433\u043E\u0432\u043E\u0440\u044F, M\u0101t\u1E5Bk\u0101 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0433\u043B\u0430\u0432\u0435\u043D\u0441\u0442\u0432\u0443\u044E\u0449\u0435\u0439 _(adhi\u1E63\u1E6Dh\u0101tr\u012B) \u015Aakti, \u0438\u043B\u0438 \u0421\u0438\u043B\u043E\u0439 <em>(\u015Bakti\u1E25)</em>. \u041F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 [M\u0101t\u1E5Bk\u0101] \u043D\u0430 \u0441\u0430\u043C\u043E\u043C \u0434\u0435\u043B\u0435 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043E\u0441\u043D\u043E\u0432\u043E\u0439 <em>(adhi\u1E63\u1E6Dh\u0101n\u0101t eva)</em> \u044D\u0442\u043E\u0433\u043E [\u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0433\u043E \u0437\u043D\u0430\u043D\u0438\u044F] <em>(tad)</em>, [\u0438] \u0442\u0430\u043A \u043A\u0430\u043A, [\u043F\u043E \u0442\u043E\u0439 \u0436\u0435 \u043F\u0440\u0438\u0447\u0438\u043D\u0435], \u043D\u0435\u0441\u043E\u043C\u043D\u0435\u043D\u043D\u043E <em>(hi)</em> \u043E\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0443\u0435\u0442 <em>(vandhyatv\u0101t)</em> \u0438\u0441\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043D\u0438\u0435 <em>(anusandhi)</em> \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0433\u043E <em>(antas)</em> \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0430 <em>(abheda)</em>, [\u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u044B\u0435] \u043F\u043E\u0437\u043D\u0430\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u044B\u0435 \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u044B <em>(j\xF1\u0101n\u0101ni)</em> \u043D\u0435 \u043D\u0430\u0445\u043E\u0434\u044F\u0442 <em>(alabdha)</em> \u043D\u0438\u043A\u0430\u043A\u043E\u0433\u043E \u043F\u043E\u043A\u043E\u044F <em>(vi\u015Br\u0101nt\u012Bni)</em> \u0434\u0430\u0436\u0435 <em>(api)</em> \u043D\u0430 \u043C\u0433\u043D\u043E\u0432\u0435\u043D\u0438\u0435 <em>(k\u1E63a\u1E47am)</em> (\u0438) \u043B\u0438\u0448\u044C <em>(eva)</em> \u043D\u0430\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u044B \u043D\u0430 \u0432\u043D\u0435\u0448\u043D\u0438\u0435 \u0432\u0435\u0449\u0438 --\u0430 \u0438\u043C\u0435\u043D\u043D\u043E, \u043D\u0430\u0440\u0443\u0436\u0443-- <em>(bahis-mukh\u0101ni)</em>. \u0418\u0442\u0430\u043A <em>(iti)</em>, \u0443\u0442\u0432\u0435\u0440\u0436\u0434\u0435\u043D\u0438\u0435 <em>(ukti\u1E25)</em>, \u0447\u0442\u043E \u0442\u0430\u043A\u043E\u0435 [\u043F\u043E\u0437\u043D\u0430\u043D\u0438\u0435] <em>(e\u1E63\u0101\u1E41)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u043E\u043A\u043E\u0432\u0430\u043C\u0438 <em>(bandhakatva)</em>, \u043F\u043E\u0438\u0441\u0442\u0438\u043D\u0435 <em>(eva)</em> \u0432\u0435\u0440\u043D\u043E <em>(yukt\u0101)</em>|</p><p>\u042D\u0442\u0430 [\u0436\u0435 \u0441\u0430\u043C\u0430\u044F \u0438\u0434\u0435\u044F] <em>(etad ca)</em> \u0431\u044B\u043B\u0430 \u043E\u0431\u043E\u0431\u0449\u0435\u043D\u043D\u043E \u043F\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u043B\u0435\u043D\u0430 <em>(sa\u1E45g\u1E5Bh\u012Btam)</em> \u0441 \u043F\u043E\u043C\u043E\u0449\u044C\u044E [\u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0435\u0433\u043E] \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0430 [Spandak\u0101rik\u0101-s] <em>(k\u0101rikay\u0101)</em>:</p><blockquote><p>&quot;... \u043F\u0440\u043E\u0438\u0437\u0432\u0435\u0434\u0435\u043D\u043D\u044B\u0439 <em>(samutthasya)</em> \u0438\u0437 \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u0430 <em>(r\u0101\u015Bi)</em> \u0441\u043B\u043E\u0432 <em>(\u015Babda... iti)</em>...&quot;|<br> [\u0421\u043C. Spandak\u0101rik\u0101-s III, 13]</p></blockquote><p>\u0438 \u0442\u0430\u043A\u0436\u0435 <em>(ca)</em> \u0432 [\u0434\u0440\u0443\u0433\u043E\u043C] \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0435 [\u044D\u0442\u043E\u0433\u043E \u0436\u0435 \u041F\u0438\u0441\u0430\u043D\u0438\u044F] <em>(k\u0101rikay\u0101)</em>:</p><blockquote><p>&quot;\u0421\u0438\u043B\u044B <em>(\u015Baktaya\u1E25)</em> \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E <em>(satata)</em> \u0433\u043E\u0442\u043E\u0432\u044B <em>(utthit\u0101\u1E25)</em> \u0441\u043A\u0440\u044B\u0432\u0430\u0442\u044C, \u0438\u043B\u0438 \u043F\u0440\u044F\u0442\u0430\u0442\u044C _(\u0101vara\u1E47e) \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u0443\u044E \u043F\u0440\u0438\u0440\u043E\u0434\u0443 _(sva-r\u016Bpa) \u044D\u0442\u043E\u0433\u043E [\u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0433\u043E \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0430] <em>(ca asya... iti)</em>...&quot;|<br> [\u0421\u043C. Spandak\u0101rik\u0101-s III, 15]</p></blockquote><p>||4||</p><hr><ol><li><p>\u0427\u0435\u043B\u043E\u0432\u0435\u043A \u043E\u0431\u043B\u0430\u0434\u0430\u0435\u0442 \u0447\u0435\u0442\u044B\u0440\u044C\u043C\u044F \u0442\u0435\u043B\u0430\u043C\u0438: (1) \u0433\u0440\u0443\u0431\u044B\u043C, \u0438\u043B\u0438 \u0444\u0438\u0437\u0438\u0447\u0435\u0441\u043A\u0438\u043C, (2) \u0442\u043E\u043D\u043A\u0438\u043C, (3) \u043A\u0430\u0443\u0437\u0430\u043B\u044C\u043D\u044B\u043C (\u043F\u0440\u0438\u0447\u0438\u043D\u043D\u044B\u043C) \u0438 (4) \u0441\u0443\u043F\u0440\u0430\u043A\u0430\u0443\u0437\u0430\u043B\u044C\u043D\u044B\u043C. \u041F\u0435\u0440\u0432\u043E\u0435 \u0445\u043E\u0440\u043E\u0448\u043E \u0437\u043D\u0430\u043A\u043E\u043C\u043E \u0432\u0441\u0435\u043C, \u0442\u0430\u043A \u0432\u0435\u0434\u044C? \u0412\u0442\u043E\u0440\u043E\u0435 \u0442\u0435\u043B\u043E \u0441\u043E\u0434\u0435\u0440\u0436\u0438\u0442 \u0432 \u0441\u0435\u0431\u0435 \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u044B\u0435 \u044D\u043D\u0435\u0440\u0433\u0438\u0438, \u0443\u043C, \u044D\u0433\u043E \u0438 \u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442. \u041A\u0430\u0443\u0437\u0430\u043B\u044C\u043D\u043E\u0435 \u0442\u0435\u043B\u043E \u0432\u044B\u0445\u043E\u0434\u0438\u0442 \u0437\u0430 \u043F\u0440\u0435\u0434\u0435\u043B\u044B \u0442\u043E\u043D\u043A\u043E\u0433\u043E \u0438 \u0441\u043E\u0434\u0435\u0440\u0436\u0438\u0442 \u043D\u0430\u043A\u043E\u043F\u043B\u0435\u043D\u043D\u044B\u0435 \u0432\u043F\u0435\u0447\u0430\u0442\u043B\u0435\u043D\u0438\u044F. &quot;\u0422\u0435\u043D\u0434\u0435\u043D\u0446\u0438\u0438&quot;, \u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u044B\u0435 \u0432 \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0438, \u044D\u0442\u043E \u043A\u0430\u043A \u0441\u0432\u043E\u0435\u0433\u043E \u0440\u043E\u0434\u0430 \u043A\u043E\u043D\u0442\u0435\u0439\u043D\u0435\u0440\u044B, \u0437\u0430\u043F\u043E\u043B\u043D\u0435\u043D\u043D\u044B\u0435 \u0445\u043E\u0440\u043E\u0448\u0435\u0439 \u0438 \u043F\u043B\u043E\u0445\u043E\u0439 \u043A\u0430\u0440\u043C\u043E\u0439... \u041E! \u044D\u0442\u043E \u0434\u043B\u0438\u043D\u043D\u0430\u044F \u0442\u0435\u043C\u0430 \u043D\u0430 \u0441\u0430\u043C\u043E\u043C \u0434\u0435\u043B\u0435. \u041F\u0440\u043E\u0441\u0442\u043E \u043F\u043E\u0439\u043C\u0438\u0442\u0435 \u043E\u0434\u043D\u043E: \u044D\u0442\u0438 \u0442\u0435\u043D\u0434\u0435\u043D\u0446\u0438\u0438, \u043D\u0430\u043A\u043E\u043F\u043B\u0435\u043D\u043D\u044B\u0435 \u0432 \u0432\u0430\u0448\u0435\u043C \u043A\u0430\u0443\u0437\u0430\u043B\u044C\u043D\u043E\u043C \u0442\u0435\u043B\u0435, \u043F\u043E\u0434\u0442\u0430\u043B\u043A\u0438\u0432\u0430\u044E\u0442 \u0432\u0430\u0441 \u043A \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u0438\u044E \u0445\u043E\u0440\u043E\u0448\u0438\u0445 \u0438 \u043F\u043B\u043E\u0445\u0438\u0445 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0439. \u0412 \u044D\u0442\u043E\u043C \u0441\u043C\u044B\u0441\u043B. \u0410\u0445, \u0434\u0430, \u0447\u0443\u0442\u044C \u043D\u0435 \u0437\u0430\u0431\u044B\u043B \u043E ... \u0441\u0443\u043F\u0440\u0430\u043A\u0430\u0443\u0437\u0430\u043B\u044C\u043D\u043E\u043C \u0442\u0435\u043B\u0435, \u044F\u0432\u043B\u044F\u044E\u0449\u0438\u043C\u0441\u044F \u0437\u043D\u0430\u043C\u0435\u043D\u0438\u0442\u044B\u043C \u0411\u0438\u043D\u0434\u0443 (Bindu), \u0438\u043B\u0438 \u0422\u043E\u0447\u043A\u043E\u0439... \u0434\u0440\u0443\u0433\u043E\u0439 \u0434\u043B\u0438\u043D\u043D\u044B\u0439 \u0438 \u0442\u0440\u0443\u0434\u043D\u044B\u0439 \u0434\u043B\u044F \u043F\u043E\u043D\u0438\u043C\u0430\u043D\u0438\u044F \u043F\u0440\u0435\u0434\u043C\u0435\u0442, \u0431\u0435\u0437 \u0441\u043E\u043C\u043D\u0435\u043D\u0438\u044F. \u0418 \u043A\u043E\u043D\u0435\u0447\u043D\u043E, \u0437\u0434\u0435\u0441\u044C \u043D\u0435\u0442 \u043D\u0435\u043E\u0431\u0445\u043E\u0434\u0438\u043C\u043E\u0441\u0442\u0438 \u043F\u0443\u0441\u043A\u0430\u0442\u044C\u0441\u044F \u0432 \u0442\u0430\u043A\u0438\u0435 \u0442\u043E\u043D\u043A\u043E\u0441\u0442\u0438 \u0438 \u0441\u043B\u043E\u0436\u043D\u043E\u0441\u0442\u0438 \u0432 \u043F\u0440\u043E\u0441\u0442\u043E\u043C \u043F\u043E\u044F\u0441\u043D\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u043C \u043F\u0440\u0438\u043C\u0435\u0447\u0430\u043D\u0438\u0438.</p></li><li><p>\u042D\u0442\u0438 \u0441\u0438\u043B\u044B \u043E\u0442\u0432\u0435\u0447\u0430\u044E\u0442 \u0437\u0430 \u0432\u0432\u0435\u0434\u0435\u043D\u0438\u0435 \u043B\u044E\u0434\u0435\u0439 \u0432 \u0437\u0430\u0431\u043B\u0443\u0436\u0434\u0435\u043D\u0438\u0435 \u0438 \u043F\u043E\u0431\u0443\u0436\u0434\u0435\u043D\u0438\u0435 \u0438\u0445 \u043A \u043C\u0438\u0440\u0441\u043A\u043E\u0439 \u0436\u0438\u0437\u043D\u0438. \u041E\u043D\u0438 \u043E\u0431\u0438\u0442\u0430\u044E\u0442 \u0432 Karandhra, \u0442\u0430\u043A\u0436\u0435 \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u043E\u043C \u043A\u0430\u043A Brahmarandhra (\u0442.\u0435. \u043E\u0442\u0432\u0435\u0440\u0441\u0442\u0438\u0435 Brahm\u0101). \u0425\u043E\u0442\u044F Brahmarandhra \u043E\u0431\u044B\u0447\u043D\u043E \u043E\u0448\u0438\u0431\u043E\u0447\u043D\u043E \u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u0442\u0441\u044F \u0437\u0430 \u0421\u0430\u0445\u0430\u0441\u0440\u0430\u0440\u0430-\u0447\u0430\u043A\u0440\u0443 (Sahasr\u0101ra-cakra), \u0442\u0435\u0445\u043D\u0438\u0447\u0435\u0441\u043A\u0438 \u043E\u043D (Brahmarandhra) \u043D\u0430\u0445\u043E\u0434\u0438\u0442\u0441\u044F \u0432 \u0441\u0430\u043C\u043E\u043C \u0446\u0435\u043D\u0442\u0440\u0435 \u0442\u0430\u043A\u043E\u0439 \u0447\u0430\u043A\u0440\u044B, \u0432 \u043E\u0431\u043B\u0430\u0441\u0442\u0438 \u043D\u0430\u0434 \u0440\u043E\u0434\u043D\u0438\u0447\u043A\u0430\u043C\u0438. \u0421\u043E\u0433\u043B\u0430\u0441\u043D\u043E \u043C\u043E\u0435\u043C\u0443 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u043C\u0443 \u043E\u043F\u044B\u0442\u0443, \u043E\u043D \u0431\u0443\u043A\u0432\u0430\u043B\u044C\u043D\u043E \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043E\u0442\u0432\u0435\u0440\u0441\u0442\u0438\u0435\u043C, \u043F\u043E\u043B\u043D\u044B\u043C \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F. \u041A\u043E\u0433\u0434\u0430 \u0447\u0435\u043B\u043E\u0432\u0435\u043A \u0432\u0445\u043E\u0434\u0438\u0442 \u0432 \u043D\u0435\u0433\u043E, \u0442\u0430\u043C \u043E\u0447\u0435\u0432\u0438\u0434\u043D\u043E \u043D\u0438\u0447\u0435\u0433\u043E \u043D\u0435\u0442, \u043D\u043E \u0441\u043E \u0432\u0440\u0435\u043C\u0435\u043D\u0435\u043C, \u043E\u043D \u043A\u0430\u043A \u0431\u044B \u0438\u0441\u043F\u044B\u0442\u044B\u0432\u0430\u0435\u0442 \u043F\u0440\u0438\u0441\u0443\u0442\u0441\u0442\u0432\u0438\u0435 \u043A\u0430\u043A\u043E\u0439-\u0442\u043E \u043C\u0435\u043C\u0431\u0440\u0430\u043D\u044B. \u0412 \u044D\u0442\u043E\u0439 \u043C\u0435\u043C\u0431\u0440\u0430\u043D\u0435 \u0435\u0441\u0442\u044C \u043D\u0430\u043F\u0440\u044F\u0436\u0435\u043D\u0438\u0435, \u0438\u043B\u0438 \u0434\u0430\u0432\u043B\u0435\u043D\u0438\u0435. \u0418 \u0428\u0438\u0432\u0430 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u044D\u0442\u043E\u0439 \u0441\u0430\u043C\u043E\u0439 \u043C\u0435\u043C\u0431\u0440\u0430\u043D\u043E\u0439, \u0432 \u0442\u043E \u0432\u0440\u0435\u043C\u044F \u043A\u0430\u043A \u0428\u0430\u043A\u0442\u0438, \u0438\u043B\u0438 \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u0430\u044F \u0421\u0438\u043B\u0430 - \u044D\u0442\u043E \u0432\u044B\u0448\u0435\u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u043E\u0435 \u043D\u0430\u043F\u0440\u044F\u0436\u0435\u043D\u0438\u0435. \u042D\u0442\u0438 \u0442\u0430\u0439\u043D\u044B \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u0440\u0430\u0437\u044A\u044F\u0441\u043D\u0435\u043D\u044B \u043C\u043D\u043E\u0439 \u0432 &quot;\u041F\u0438\u0441\u0430\u043D\u0438\u044F (\u0438\u0441\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043D\u0438\u0435)/\u015Aivas\u016Btravimar\u015Bin\u012B&quot; \u0432 \u0440\u0430\u0437\u0434\u0435\u043B\u0435 \u0422\u0440\u0438\u043A\u0430.</p></li></ol></div>',1),h=[r];function o(s,n,k,d,p,u){return e(),m("div",null,h)}var y=a(i,[["render",o]]);export{l as __pageData,y as default};
